const text = $input.item.json.content[0].text;
const match = text.match(/\{[^{}]*\}/s);
if (match) {
  try {
    return JSON.parse(match[0]);
  } catch (e) {}
}
return {script: text, prompt: 'Cinematic POV shot', duration: 10};

const pollResult = $json.data || $json;
let videoUrl = null;
const taskId = pollResult.taskId || $('Generate Video Kie').item.json.data.taskId;

// Veo3.1 response structure: successFlag (0=generating, 1=success, 2/3=failed)
if (pollResult.successFlag === 1 && pollResult.response?.resultUrls) {
  videoUrl = pollResult.response.resultUrls[0] || null;
}

return {
  success: pollResult.successFlag === 1,
  videoUrl: videoUrl,
  taskId: taskId,
  script: $('Parse Script').item.json.script,
  state: pollResult.successFlag === 1 ? 'success' : (pollResult.successFlag === 2 || pollResult.successFlag === 3 ? 'fail' : 'generating'),
  message: pollResult.successFlag === 1 ? 'Video ready' : (pollResult.successFlag === 2 || pollResult.successFlag === 3 ? pollResult.errorMessage || 'Video generation failed' : 'Processing...')
};

