// Return taskId immediately so frontend can start polling
const generateResult = $('Generate Video Kie1').item.json;
const taskId = generateResult.data?.taskId || generateResult.taskId;

if (!taskId) {
  throw new Error('No taskId received from Veo3.1 API');
}

return {
  taskId: taskId,
  state: 'generating',
  message: 'Video generation started. Polling for status...',
  script: $('Parse Script').item.json.script || ''
};

// Track how many times we've polled for video status
// Skip video if it takes longer than 30 minutes (10 retries)

const videoData = $input.first().json;
const MAX_RETRIES = 10; // 10 * 3 minutes = 30 minutes max

// Get retry count from the data itself (passed through the loop)
const retryCount = videoData.retryCount || 0;

console.log(`Video polling attempt: ${retryCount + 1}/${MAX_RETRIES}`);
console.log('Video data:', JSON.stringify(videoData, null, 2));

// Check if we've exceeded max retries
if (retryCount >= MAX_RETRIES) {
  console.log('⚠️  Max retries reached, skipping video');

  return [{
    json: {
      skipVideo: true,
      videoReady: false,
      retryCount: 0,
      reason: 'Video generation timeout after 30 minutes',
      data: videoData.data || {}
    }
  }];
}

// Check success flag
const successFlag = videoData.data?.successFlag;
const code = videoData.code;

console.log(`API Code: ${code}`);
console.log(`Success flag: ${successFlag} (0=generating, 1=success, 2/3=failed)`);

if (successFlag === 1) {
  // Success!
  console.log('✅ Video generation complete!');

  return [{
    json: {
      ...videoData,
      skipVideo: false,
      videoReady: true,
      retryCount: 0
    }
  }];
} else if (successFlag === 2 || successFlag === 3) {
  // Failed!
  console.log('❌ Video generation failed');

  return [{
    json: {
      ...videoData,
      skipVideo: true,
      videoReady: false,
      retryCount: 0,
      reason: 'Video generation failed (successFlag: ' + successFlag + ')'
    }
  }];
} else if (code && code !== 200) {
  // API error
  console.log('❌ API error: code ' + code);

  return [{
    json: {
      ...videoData,
      skipVideo: true,
      videoReady: false,
      retryCount: 0,
      reason: 'API error: ' + (videoData.msg || 'Unknown error')
    }
  }];
}

// Still generating, increment counter and continue polling
return [{
  json: {
    ...videoData,
    skipVideo: false,
    videoReady: false,
    continuePolling: true,
    retryCount: retryCount + 1
  }
}];

